import{_ as e,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as s,o as i,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"新增 Yandex 渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/yandex.md","filePath":"zh-TW/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"zh-TW/upload/yandex.md"};function p(c,t,h,x,b,u){return i(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="新增-yandex-渠道" tabindex="-1">新增 Yandex 渠道 <a class="header-anchor" href="#新增-yandex-渠道" aria-label="Permalink to &quot;新增 Yandex 渠道&quot;">​</a></h1><h2 id="新增前要準備什麼" tabindex="-1">新增前要準備什麼 <a class="header-anchor" href="#新增前要準備什麼" aria-label="Permalink to &quot;新增前要準備什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要準備</th><th>用途</th></tr></thead><tbody><tr><td>Yandex 帳號</td><td>登入並授權 Yandex Disk</td></tr><tr><td>Yandex OAuth App</td><td>取得 <code>Client ID</code> 和 <code>Client Secret</code></td></tr><tr><td>目前 ImgBed 網域</td><td>設定授權回呼網址</td></tr><tr><td>可用的 Yandex Disk 空間</td><td>實際存放檔案</td></tr></tbody></table><h2 id="新增步驟" tabindex="-1">新增步驟 <a class="header-anchor" href="#新增步驟" aria-label="Permalink to &quot;新增步驟&quot;">​</a></h2><h3 id="第一步-建立-yandex-oauth-app" tabindex="-1">第一步：建立 Yandex OAuth App <a class="header-anchor" href="#第一步-建立-yandex-oauth-app" aria-label="Permalink to &quot;第一步：建立 Yandex OAuth App&quot;">​</a></h3><ol><li>打開 Yandex OAuth 建立應用頁：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>如果先跳到登入頁，先登入 Yandex 帳號。</li><li>建立新 App。</li><li>取一個自己看得懂的名稱，例如 <code>imgbed-yandex</code>。</li><li>在設定裡找到回呼網址。</li><li>填：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的網域/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="第二步-確認授權範圍" tabindex="-1">第二步：確認授權範圍 <a class="header-anchor" href="#第二步-確認授權範圍" aria-label="Permalink to &quot;第二步：確認授權範圍&quot;">​</a></h3><p>目前 ImgBed 的 Yandex 整合建議保留 <code>Yandex.Disk REST API</code> 下這 4 個權限：</p><table tabindex="0"><thead><tr><th>權限</th><th>作用</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>讓系統把檔案存到 App 目錄</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>讀取檔案與下載連結</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>上傳檔案、建目錄、刪檔</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>讀取磁碟容量、已用空間等資訊</td></tr></tbody></table><p>如果也看到 <code>Yandex ID API</code> 底下的姓名、Email 權限，可以視需求保留；核心上傳、下載、刪除、查容量主要依賴上面 4 個 Disk 權限。</p><p><img src="'+e+'" alt="設定 Yandex Disk 權限" loading="lazy"></p><h3 id="第三步-記下-app-資訊" tabindex="-1">第三步：記下 App 資訊 <a class="header-anchor" href="#第三步-記下-app-資訊" aria-label="Permalink to &quot;第三步：記下 App 資訊&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Yandex 後台欄位</th><th>ImgBed 欄位</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="記錄 Client ID 和 Secret" loading="lazy"></p><h3 id="第四步-回-imgbed-填寫-yandex-渠道" tabindex="-1">第四步：回 ImgBed 填寫 Yandex 渠道 <a class="header-anchor" href="#第四步-回-imgbed-填寫-yandex-渠道" aria-label="Permalink to &quot;第四步：回 ImgBed 填寫 Yandex 渠道&quot;">​</a></h3><table tabindex="0"><thead><tr><th>頁面欄位</th><th>填寫內容</th></tr></thead><tbody><tr><td>渠道名稱</td><td>自己取，例如 <code>Yandex主帳號</code></td></tr><tr><td>Client ID</td><td>Yandex App 的 <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex App 的 <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>先留空</td></tr><tr><td>根目錄</td><td>選填，預設 <code>imgbed</code></td></tr></tbody></table><p><img src="'+d+'" alt="編輯渠道設定" loading="lazy"></p><h3 id="第五步-取得-refresh-token" tabindex="-1">第五步：取得 Refresh Token <a class="header-anchor" href="#第五步-取得-refresh-token" aria-label="Permalink to &quot;第五步：取得 Refresh Token&quot;">​</a></h3><ol><li>在 ImgBed 點「取得 Token」。</li><li>登入要綁定的 Yandex 帳號。</li><li>依提示授權。</li><li>授權成功後，回呼頁會顯示 <code>Refresh Token</code>。</li><li>複製它。</li><li>回到 ImgBed，貼到 <code>Refresh Token</code> 欄位。</li></ol><p><img src="'+n+`" alt="授權後複製 Refresh Token" loading="lazy"></p><h3 id="第六步-儲存渠道" tabindex="-1">第六步：儲存渠道 <a class="header-anchor" href="#第六步-儲存渠道" aria-label="Permalink to &quot;第六步：儲存渠道&quot;">​</a></h3><p>欄位填好後直接儲存。</p><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打開 Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; 建立 App</span></span>
<span class="line"><span>-&gt; 設定回呼 https://你的網域/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; 確認 Disk 權限</span></span>
<span class="line"><span>-&gt; 複製 Client ID 和 Client Secret</span></span>
<span class="line"><span>-&gt; 回 ImgBed 填 Client ID / Client Secret</span></span>
<span class="line"><span>-&gt; 點取得 Token</span></span>
<span class="line"><span>-&gt; 複製 Refresh Token</span></span>
<span class="line"><span>-&gt; 貼回 ImgBed 儲存</span></span></code></pre></div>`,27)])])}const _=s(r,[["render",p]]);export{k as __pageData,_ as default};
